logger.message:
#[%dw 2.0
output application/json
---
{
    step: "Debug generate token",
    data: {
        business: {},
        technical: {
            refreshToken: vars.refreshToken,
            accessToken: vars.accessToken
        }
    }
}]

#[%dw 2.0
output application/json
---
{
    step: "After retrieve appointments",
    data: {
        business: {
        	countAppointments: sizeOf(vars.appointments)
        },
        technical: {}
    }
}]

#[%dw 2.0
output application/json indent=false
---
{
    step: "Debug retrieve appointments",
    data: {
        business: {},
        technical: {
        	firstAppointment: vars.appointments[0]
        }
    }
}]

#[%dw 2.0
output application/json indent=false
---
{
    step: "Debug map to Calendar Data Model",
    data: {
        business: {
        	patientId: vars.patientId
        },
        technical: {
        	firstCDM: vars.calendarDataModel[0]
        }
    }
}]
